#!/usr/bin/env python3
import base64, os, sys
if not os.path.isdir("assets"): sys.exit("Run from BatKnock root")

with open("assets/icon.png", "wb") as f:
    f.write(base64.b64decode(""))
print("OK assets/icon.png")

with open("assets/adaptive-icon.png", "wb") as f:
    f.write(base64.b64decode(""))
print("OK assets/adaptive-icon.png")

print()
print("Now rebuild:")
print("  eas build --platform all --profile production")
print("  eas submit --platform ios --profile production")
print("  eas submit --platform android --profile production")
